+
+/**
+ * `SessionManager` constructor.
+ *
+ * @param {Object} options
+ * @api private
+ */
+function SessionManager(options) {
+  options = options || {};
+  this._key = options.key || 'passport';
+}
+
+
+/**
+ * Log in `user` and establish a session.
+ *
+ * @param {IncomingMessage} req
+ * @param {Object} user
+ * @param {Object} options
+ * @param {Function} cb
+ * @api private
+ */
+SessionManager.prototype.logIn = function(req, user, options, cb) {
+  if (typeof options == 'function') {
+    cb = options;
+    options = {};
+  }
+  options = options || {};
+  
+  if (!req.session) { return cb(new Error('Login sessions require session support. Did you forget to use `express-session` middleware?')); }
+  
+  var prevSession = req.session;
+  req.session.regenerate(function(err) {
+    if (err) {
+      return cb(err);
+    }
+    
+    if (options.keepSessionInfo) {
+      merge(req.session, prevSession);
+    }
+    if (!req.session[self._key]) {
+      req.session[self._key] = {};
+    }
+    req.session[self._key].user = user;
+    cb();
+  });
+};
+
+
+/**
+ * Log out `user` and remove from the session.
+ *
+ * @param {IncomingMessage} req
+ * @param {Object} options
+ * @param {Function} cb
+ * @api private
+ */
+SessionManager.prototype.logOut = function(req, options, cb) {
+  if (typeof options == 'function') {
+    cb = options;
+    options = {};
+  }
+  options = options || {};
+  
+  if (!req.session) { return cb(new Error('Login sessions require session support. Did you forget to use `express-session` middleware?')); }
+  
+  if (req.session[this._key]) {
+    delete req.session[this._key].user;
+  }
+  var prevSession = req.session;
+  
+  req.session.save(function(err) {
+    if (err) {
+      return cb(err)
+    }
+    
+    req.session.regenerate(function(err) {
+      if (err) {
+        return cb(err);
+      }
+      if (options.keepSessionInfo) {
+        merge(req.session, prevSession);
+      }
+      cb();
+    });
+  });
+};
+
+module.exports = SessionManager;
